args.sparql:
SELECT ?medalLabel WHERE {
  ?goldMedalist wdt:P21 wd:Q6581072 ;  # Female
             wdt:P2090 wd:Q15725551 ;  # Gold medal
             wdt:P1545 wd:Q2734063 .  # 1994 European Judo Championships

  ?goldMedalist wdt:P1545 ?event .
  ?event wdt:P276 wd:Q133116 .  # Hamilton, Ontario

  ?goldMedalist wdt:P2090 ?medalType .
  OPTIONAL { ?medalType rdfs:label ?medalLabel FILTER (lang(?medalLabel) = "en") }
}

SELECT ?medalLabel WHERE {
  ?goldMedalist wdt:P21 wd:Q6581072 ;  # Female
             wdt:P2090 wd:Q15725551 ;  # Gold medal
             wdt:P1545 wd:Q2734063 .  # 1994 European Judo Championships

  ?event wdt:P1545 wd:Q2734063 ;
         wdt:P576 wd:Q133116 .  # Location: Hamilton, Ontario (using P576 instead of P276)

  ?goldMedalist wdt:P2090 ?medalType .
  OPTIONAL { ?medalType rdfs:label ?medalLabel FILTER (lang(?medalLabel) = "en") }
}

SELECT DISTINCT ?medalLabel WHERE {
  wd:Q2734063 wdt:P576 wd:Q133116 .
  ?goldMedalist wdt:P2090 wd:Q15725551 ;
               wdt:P1545 wd:Q2734063 ;
               wdt:P21 wd:Q6581072 .
  wd:Q15725551 rdfs:label ?medalLabel FILTER (lang(?medalLabel) = "en")
}

SELECT ?medalLabel WHERE {
  wd:Q2734063 wdt:P276 wd:Q133116 .  # Event held in Hamilton (location)
  ?goldMedalist wdt:P2090 wd:Q15725551 ;  # Gold medal
               wdt:P1545 wd:Q2734063 .
  wd:Q15725551 rdfs:label ?medalLabel FILTER (lang(?medalLabel) = "en")
}

SELECT ?personLabel WHERE {
  wd:Q2734063 wdt:P1545 ?person.
  ?person wdt:P2090 wd:Q15725551.
  ?person wdt:P21 wd:Q6581072.
  ?person rdfs:label ?personLabel FILTER (lang(?personLabel) = "en")
}

SELECT ?participant ?participantLabel WHERE {
  ?participant wdt:P1545 wd:Q2734063 ;  # Participant is part of event
              wdt:P2090 wd:Q15725551 ;  # Gold medal
              wdt:P21 wd:Q6581072 .     # Female
  ?participant rdfs:label ?participantLabel FILTER (lang(?participantLabel) = "en")
}

SELECT ?locationLabel WHERE {
  wd:Q2734063 wdt:P276 ?location .
  ?location rdfs:label ?locationLabel FILTER (lang(?locationLabel) = "en")
}

SELECT ?event ?eventLabel WHERE {
  ?event wdt:P276 wd:Q133116 .  # Held in Hamilton, Ontario
  ?event rdfs:label ?eventLabel FILTER (lang(?eventLabel) = "en")
}
